// src/pages/TimetablePage.js
import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { DAYS, PERIOD_TIMES } from '../data/initialData';

export default function TimetablePage() {
  const { timetable, staff, addTimetableEntry, removeTimetableEntry, currentUser } = useApp();
  const [selectedStaff, setSelectedStaff] = useState(
    currentUser.role !== 'admin' ? currentUser.id : staff[0]?.id || ''
  );
  const [newEntry, setNewEntry] = useState({ day: 'Monday', period: 1, class: '' });
  const [showAdd, setShowAdd] = useState(false);
  const [viewMode, setViewMode] = useState('grid'); // grid or list

  const isAdmin = currentUser.role === 'admin';
  const displayStaffId = isAdmin ? selectedStaff : currentUser.id;
  const slots = timetable[displayStaffId] || [];
  const selectedStaffMember = staff.find(s => s.id === parseInt(displayStaffId));

  const handleAdd = () => {
    if (!newEntry.class.trim()) { alert('Please enter class name'); return; }
    addTimetableEntry(parseInt(displayStaffId), { ...newEntry, period: parseInt(newEntry.period), time: PERIOD_TIMES[newEntry.period] });
    setNewEntry({ day: 'Monday', period: 1, class: '' });
    setShowAdd(false);
  };

  // Build grid: day x period
  const gridData = {};
  DAYS.forEach(day => {
    gridData[day] = {};
    [1, 2, 3, 4].forEach(p => { gridData[day][p] = null; });
  });
  slots.forEach((slot, idx) => {
    if (gridData[slot.day]) {
      gridData[slot.day][slot.period] = { ...slot, idx };
    }
  });

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div>
          <h1 style={styles.title}>📅 Timetable</h1>
          <p style={styles.subtitle}>Manage faculty class schedules</p>
        </div>
        {isAdmin && (
          <button style={styles.addBtn} onClick={() => setShowAdd(!showAdd)}>
            + Add Period
          </button>
        )}
      </div>

      {/* Staff Selector */}
      {isAdmin && (
        <div style={styles.staffBar}>
          {staff.map(t => (
            <button
              key={t.id}
              onClick={() => { setSelectedStaff(t.id); setShowAdd(false); }}
              style={{
                ...styles.staffChip,
                ...(displayStaffId === t.id ? styles.staffChipActive : {}),
              }}
            >
              <span style={styles.chipAvatar}>{t.name[0]}</span>
              {t.name.split(' ')[1]}
            </button>
          ))}
        </div>
      )}

      {selectedStaffMember && (
        <div style={styles.staffInfo}>
          <div style={styles.infoAvatar}>{selectedStaffMember.name[0]}</div>
          <div>
            <div style={styles.infoName}>{selectedStaffMember.name}</div>
            <div style={styles.infoSub}>{selectedStaffMember.subject} · {selectedStaffMember.department}</div>
          </div>
          <div style={styles.slotCount}>{slots.length} periods/week</div>
        </div>
      )}

      {/* Add Entry Form */}
      {showAdd && isAdmin && (
        <div style={styles.addForm}>
          <h3 style={styles.addTitle}>Add New Period</h3>
          <div style={styles.addRow}>
            <div style={styles.formGroup}>
              <label style={styles.label}>Day</label>
              <select style={styles.select} value={newEntry.day} onChange={e => setNewEntry({ ...newEntry, day: e.target.value })}>
                {DAYS.map(d => <option key={d} value={d}>{d}</option>)}
              </select>
            </div>
            <div style={styles.formGroup}>
              <label style={styles.label}>Period</label>
              <select style={styles.select} value={newEntry.period} onChange={e => setNewEntry({ ...newEntry, period: e.target.value })}>
                {[1, 2, 3, 4].map(p => <option key={p} value={p}>Period {p} ({PERIOD_TIMES[p]})</option>)}
              </select>
            </div>
            <div style={styles.formGroup}>
              <label style={styles.label}>Class</label>
              <input style={styles.input} placeholder="e.g. 11A" value={newEntry.class} onChange={e => setNewEntry({ ...newEntry, class: e.target.value })} />
            </div>
            <div style={styles.formGroup}>
              <label style={styles.label}>&nbsp;</label>
              <div style={{ display: 'flex', gap: 8 }}>
                <button style={styles.saveBtn} onClick={handleAdd}>Save</button>
                <button style={styles.cancelBtn} onClick={() => setShowAdd(false)}>Cancel</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Timetable Grid */}
      <div style={styles.gridWrapper}>
        <table style={styles.grid}>
          <thead>
            <tr>
              <th style={styles.cornerCell}>Day / Period</th>
              {[1, 2, 3, 4].map(p => (
                <th key={p} style={styles.headCell}>
                  <div>Period {p}</div>
                  <div style={styles.periodTime}>{PERIOD_TIMES[p]}</div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {DAYS.map(day => (
              <tr key={day}>
                <td style={styles.dayCell}>{day}</td>
                {[1, 2, 3, 4].map(p => {
                  const slot = gridData[day]?.[p];
                  return (
                    <td key={p} style={styles.slotCell}>
                      {slot ? (
                        <div style={styles.slotBox}>
                          <div style={styles.slotClass}>Class {slot.class}</div>
                          {isAdmin && (
                            <button
                              style={styles.removeBtn}
                              onClick={() => removeTimetableEntry(displayStaffId, slot.idx)}
                            >✕</button>
                          )}
                        </div>
                      ) : (
                        <div style={styles.emptySlot}>—</div>
                      )}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Stats */}
      <div style={styles.statsRow}>
        <div style={styles.statChip}>📊 Total: {slots.length} periods/week</div>
        <div style={styles.statChip}>📚 Classes: {[...new Set(slots.map(s => s.class))].join(', ') || 'None'}</div>
      </div>
    </div>
  );
}

